```python
import math
import nltk
from nltk.util import ngrams
from nltk.tokenize import word_tokenize
from collections import defaultdict

class NgramModel:
    def __init__(self, n):
        self.n = n
        self.model = defaultdict(dict)

    def train(self, text):
        tokens = word_tokenize(text)
        for i in range(len(tokens) - self.n + 1):
            ngram = tuple(tokens[i:i + self.n])
            next_token = tokens[i + self.n]
            if ngram not in self.model:
                self.model[ngram] = {}
            if next_token not in self.model[ngram]:
                self.model[ngram][next_token] = 0
            self.model[ngram][next_token] += 1

    def calculate_probability(self, ngram, next_token):
        if ngram not in self.model or next_token not in self.model[ngram]:
            return 0
        return self.model[ngram][next_token] / sum(self.model[ngram].values())

